CODE_EXAMPLE:
// Before
int withinRange(int low, int high) {
  return (low <= quantity) && (quantity <= high);
}

// Usage
withinRange(range.getLow(), range.getHigh());

// After
int withinRange(Range range) {
  return (range.getLow() <= quantity) && (quantity <= range.getHigh());
}

// Usage
withinRange(range);

UNIT_TEST_EXAMPLE:
@Test
public void testPreserveWhole() {
  Range range = new Range(5, 10);
  assertTrue(withinRange(range));
}
